-- ============================================================================
-- V10 — Real ValoCase catalog seed (generated from src/main/resources/catalog/*.json)
-- ============================================================================
-- Replaces the slow startup importer with a deterministic, one-time Flyway seed.
-- Upserts real skins, the 6 real cases and their drop pools, then DEACTIVATES
-- (does not delete) the V3 sample_* rows. Touches catalog tables only; no
-- player-owned tables (accounts, wallets, inventories, battles, upgrades,
-- transactions, case openings) are referenced.
-- ============================================================================

-- Real skins (1136). Upsert by primary key id.
ON CONFLICT (id) DO UPDATE SET
    display_name = EXCLUDED.display_name,
    weapon       = EXCLUDED.weapon,
    rarity       = EXCLUDED.rarity,
    vp_value     = EXCLUDED.vp_value,
    image_ref    = EXCLUDED.image_ref,
    active       = EXCLUDED.active;

-- Real cases (6). Upsert by primary key id.
ON CONFLICT (id) DO UPDATE SET
    display_name = EXCLUDED.display_name,
    price_vp     = EXCLUDED.price_vp,
    image_ref    = EXCLUDED.image_ref,
    active       = EXCLUDED.active;

-- Case drop-pool entries (100). Upsert by the (case_id, skin_id) unique key.
ON CONFLICT (case_id, skin_id) DO UPDATE SET
    weight = EXCLUDED.weight;

-- Neutralize the V3 sample data (deactivate, do NOT delete).
UPDATE case_definitions SET active = FALSE WHERE id = 'sample_case_starter';
UPDATE skins SET active = FALSE WHERE id IN (
    'sample_skin_phantom_neon', 'sample_skin_vandal_dragon', 'sample_skin_classic_basic');
